[{"operationName":"viewerLeagues","variables":{},"query":"query viewerLeagues {
  viewer {
    id
    __typename
    ... on Member {
      leagues {
        id
        slug
        isElectronicPaymentsEnabled
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
  }
}
"},{"operationName":"sidebar","variables":{},"query":"query sidebar {
  viewer {
    id
    ... on Member {
      leagues {
        id
        slug
        name
        isDefault
        isElectronicPaymentsEnabled
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        id
        slug
        name
        __typename
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"DisableCheck","variables":{},"query":"query DisableCheck {
  feature(key: "EmergencyNotice")
  league(id: 589) {
    news(limit: 1) {
      id
      title
      __typename
    }
    __typename
  }
}
"},{"operationName":"TournamentBannerQuery","variables":{},"query":"query TournamentBannerQuery {
  viewer {
    id
    ... on Member {
      registrationWindows(status: [IN_PROGRESS, CLOSED]) {
        id
        tournamentPlayers(mine: true, registered: false) {
          ... on TeamTournamentPlayer {
            id
            __typename
          }
          ... on SinglesTournamentPlayer {
            id
            __typename
          }
          ... on WeeklyTournamentPlayer {
            id
            __typename
          }
          ... on USAMTournamentPlayer {
            id
            __typename
          }
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"MembershipBannerQuery","variables":{},"query":"query MembershipBannerQuery {
  viewer {
    ... on Member {
      id
      fee {
        message
        __typename
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"ViewerQuery","variables":{},"query":"query ViewerQuery {
  viewer {
    __typename
    id
    firstName
    lastName
    emailAddress
  }
}
"},{"operationName":"FeatureCheck","variables":{},"query":"query FeatureCheck {
  features {
    id
    name
    active
    __typename
  }
}
"},{"operationName":"UseGetViewerQuery","variables":{},"query":"query UseGetViewerQuery {
  viewer {
    id
    ... on Member {
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
    __typename
  }
}
"}]

[{"operationName":"RaygunUserTracking","variables":{},"query":"query RaygunUserTracking {
  viewer {
    id
    ... on ExternalStaff {
      firstName
      lastName
      emailAddress
      __typename
    }
    ... on NationalOfficeStaff {
      firstName
      lastName
      emailAddress
      __typename
    }
    ... on Member {
      firstName
      lastName
      emailAddress
      __typename
    }
    __typename
  }
}
"}]

[{"operationName":"LiveStream","variables":{},"query":"query LiveStream {
  liveStream {
    __typename
    feeds {
      __typename
      ... on YoutubeLive {
        title
        description
        publishTime
        embed
        thumbnails {
          url
          height
          width
          __typename
        }
        __typename
      }
    }
  }
}
"},{"operationName":"getTournament","variables":{"id":52828},"query":"query getTournament($id: Int!) {
  tournament(id: $id) {
    id
    name
    description
    tournamentType
    startTime
    endTime
    fees
    teamCount
    tournamentTypeName
    type
    webEventLink
    event {
      id
      visible
      name
      hostName
      additionalInfo
      hostPhone
      link
      registrationWindow {
        id
        status
        __typename
      }
      league {
        id
        name
        slug
        __typename
      }
      __typename
    }
    hostLocation {
      id
      phone
      address {
        id
        name
        city
        zip
        address1
        address2
        latitude
        longitude
        stateProvince {
          id
          name
          __typename
        }
        country {
          id
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
"}]
